#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding pre-operative-assessment-by-patient (22 tables)..."

cargo loco generate scaffold patient \
    first_name:text! \
    last_name:text! \
    date_of_birth:date! \
    sex:text! \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    weight:double \
    height:double \
    bmi:double \
    planned_procedure:text! \
    procedure_urgency:text! \
    status:text! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    --htmx

cargo loco generate scaffold assessment_cardiovascular \
    assessment:references \
    hypertension:text! \
    hypertension_controlled:text! \
    ischemic_heart_disease:text! \
    ihd_details:text! \
    heart_failure:text! \
    heart_failure_nyha:text! \
    valvular_disease:text! \
    valvular_details:text! \
    arrhythmia:text! \
    arrhythmia_type:text! \
    pacemaker:text! \
    recent_mi:text! \
    recent_mi_weeks:int \
    --htmx

cargo loco generate scaffold assessment_respiratory \
    assessment:references \
    asthma:text! \
    asthma_frequency:text! \
    copd:text! \
    copd_severity:text! \
    osa:text! \
    osa_cpap:text! \
    smoking:text! \
    smoking_pack_years:int \
    recent_urti:text! \
    --htmx

cargo loco generate scaffold assessment_renal \
    assessment:references \
    ckd:text! \
    ckd_stage:text! \
    dialysis:text! \
    dialysis_type:text! \
    --htmx

cargo loco generate scaffold assessment_hepatic \
    assessment:references \
    liver_disease:text! \
    cirrhosis:text! \
    child_pugh_score:text! \
    hepatitis:text! \
    hepatitis_type:text! \
    --htmx

cargo loco generate scaffold assessment_endocrine \
    assessment:references \
    diabetes:text! \
    diabetes_control:text! \
    diabetes_on_insulin:text! \
    thyroid_disease:text! \
    thyroid_type:text! \
    adrenal_insufficiency:text! \
    --htmx

cargo loco generate scaffold assessment_neurological \
    assessment:references \
    stroke_or_tia:text! \
    stroke_details:text! \
    epilepsy:text! \
    epilepsy_controlled:text! \
    neuromuscular_disease:text! \
    neuromuscular_details:text! \
    raised_icp:text! \
    --htmx

cargo loco generate scaffold assessment_haematological \
    assessment:references \
    bleeding_disorder:text! \
    bleeding_details:text! \
    on_anticoagulants:text! \
    anticoagulant_type:text! \
    sickle_cell_disease:text! \
    sickle_cell_trait:text! \
    anaemia:text! \
    --htmx

cargo loco generate scaffold assessment_musculoskeletal_airway \
    assessment:references \
    rheumatoid_arthritis:text! \
    cervical_spine_issues:text! \
    limited_neck_movement:text! \
    limited_mouth_opening:text! \
    dental_issues:text! \
    dental_details:text! \
    previous_difficult_airway:text! \
    mallampati_score:text! \
    --htmx

cargo loco generate scaffold assessment_gastrointestinal \
    assessment:references \
    gord:text! \
    hiatus_hernia:text! \
    nausea:text! \
    --htmx

cargo loco generate scaffold assessment_medication \
    assessment:references \
    name:text! \
    dose:text! \
    frequency:text! \
    sort_order:int! \
    --htmx

cargo loco generate scaffold assessment_allergy \
    assessment:references \
    allergen:text! \
    reaction:text! \
    severity:text! \
    sort_order:int! \
    --htmx

cargo loco generate scaffold assessment_previous_anaesthesia \
    assessment:references \
    previous_anaesthesia:text! \
    anaesthesia_problems:text! \
    anaesthesia_problem_details:text! \
    family_mh_history:text! \
    family_mh_details:text! \
    ponv:text! \
    --htmx

cargo loco generate scaffold assessment_social_history \
    assessment:references \
    alcohol:text! \
    alcohol_units_per_week:int \
    recreational_drugs:text! \
    drug_details:text! \
    --htmx

cargo loco generate scaffold assessment_functional_capacity \
    assessment:references \
    exercise_tolerance:text! \
    estimated_mets:double \
    mobility_aids:text! \
    recent_decline:text! \
    --htmx

cargo loco generate scaffold assessment_pregnancy \
    assessment:references \
    possibly_pregnant:text! \
    pregnancy_confirmed:text! \
    gestation_weeks:int \
    --htmx

cargo loco generate scaffold asa_rule \
    system:text! \
    description:text! \
    grade:int! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    asa_grade:int! \
    asa_grade_override:int \
    override_reason:text! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    asa_rule:references \
    rule_system:text! \
    rule_description:text! \
    rule_grade:int! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:text! \
    category:text! \
    message:text! \
    priority:text! \
    --htmx

echo "Done."
